def median(values: list[float]) -> float:
    if not values:
        raise ValueError("median() arg is an empty sequence")
    values = sorted(values)
    n = len(values)
    mid = n // 2
    if n % 2 == 1:
        return values[mid]
    else:
        return (values[mid - 1] + values[mid]) / 2.0

